"""sklearn.calibration — Probability calibration for classifiers."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, clone


class CalibratedClassifierCV(BaseEstimator, ClassifierMixin):
    """Probability calibration with cross-validation.

    Wraps a classifier and calibrates its predicted probabilities using
    either Platt scaling (sigmoid) or isotonic regression.

    Parameters
    ----------
    estimator : classifier, default=None
    method : str, default='sigmoid'
        'sigmoid' for Platt scaling, 'isotonic' for isotonic regression.
    cv : int, default=5
        Number of cross-validation folds.
    """

    def __init__(self, estimator=None, method='sigmoid', cv=5):
        self.estimator = estimator
        self.method = method
        self.cv = cv

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        self.classes_ = np.unique(y)
        n = X.shape[0]
        # Simple approach: fit base estimator on all data, then calibrate
        self.base_estimator_ = clone(self.estimator)
        self.base_estimator_.fit(X, y)

        # Get raw scores
        if hasattr(self.base_estimator_, 'decision_function'):
            raw = self.base_estimator_.decision_function(X)
        elif hasattr(self.base_estimator_, 'predict_proba'):
            proba = self.base_estimator_.predict_proba(X)
            raw = proba[:, 1] if proba.ndim > 1 else proba
        else:
            raw = self.base_estimator_.predict(X).astype(float)

        if raw.ndim > 1:
            raw = raw[:, 0]

        # Fit calibration map
        binary_y = (y == self.classes_[-1]).astype(float)
        if self.method == 'sigmoid':
            self._fit_sigmoid(raw, binary_y)
        else:
            self._fit_isotonic(raw, binary_y)
        return self

    def _fit_sigmoid(self, raw, y):
        """Platt scaling: fit a logistic sigmoid a*f + b."""
        from sklearn.linear_model import LogisticRegression
        lr = LogisticRegression(max_iter=1000)
        lr.fit(raw.reshape(-1, 1), y)
        self.calibrator_ = lr

    def _fit_isotonic(self, raw, y):
        """Isotonic regression calibration."""
        order = np.argsort(raw)
        self.iso_x_ = raw[order]
        self.iso_y_ = y[order]
        # Pool Adjacent Violators
        n = len(self.iso_y_)
        result = self.iso_y_.copy().astype(float)
        w = np.ones(n)
        blocks = list(range(n))
        i = 0
        while i < len(blocks) - 1:
            if result[blocks[i]] > result[blocks[i + 1]]:
                # merge
                wsum = w[blocks[i]] + w[blocks[i + 1]]
                val = (w[blocks[i]] * result[blocks[i]] + w[blocks[i + 1]] * result[blocks[i + 1]]) / wsum
                result[blocks[i]] = val
                w[blocks[i]] = wsum
                blocks.pop(i + 1)
                if i > 0:
                    i -= 1
            else:
                i += 1
        expanded = np.zeros(n)
        for idx, b in enumerate(blocks):
            # fill forward
            end = blocks[idx + 1] if idx + 1 < len(blocks) else n
            expanded[b:end] = result[b]
        self.iso_fitted_y_ = expanded

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        if hasattr(self.base_estimator_, 'decision_function'):
            raw = self.base_estimator_.decision_function(X)
        elif hasattr(self.base_estimator_, 'predict_proba'):
            proba = self.base_estimator_.predict_proba(X)
            raw = proba[:, 1] if proba.ndim > 1 else proba
        else:
            raw = self.base_estimator_.predict(X).astype(float)
        if raw.ndim > 1:
            raw = raw[:, 0]

        if self.method == 'sigmoid':
            p = self.calibrator_.predict_proba(raw.reshape(-1, 1))
            if p.ndim > 1 and p.shape[1] == 2:
                p1 = p[:, 1]
            else:
                p1 = p.ravel()
        else:
            p1 = np.interp(raw, self.iso_x_, self.iso_fitted_y_)
            p1 = np.clip(p1, 0, 1)

        return np.column_stack([1 - p1, p1])

    def predict(self, X):
        proba = self.predict_proba(X)
        return self.classes_[np.argmax(proba, axis=1)]
